/**
 * Blog Page — Lists all blog posts with excerpts.
 * Public page (no auth required), dark theme matching Aura Alpha design.
 */
import { Link } from 'react-router-dom';
import usePageTitle from '../hooks/usePageTitle';
import SEO from '@/components/SEO';
import PublicNav from '@/components/PublicNav';
import PublicFooter from '@/components/PublicFooter';
import { tokens } from '../styles/tokens';
import blogPosts from '../data/blog-posts.json';
import s from './BlogPage.module.css';

const TAG_COLORS = {
  'algorithmic-trading': tokens.color.blue,
  'beginner': tokens.color.green,
  'education': tokens.color.amber,
  'machine-learning': tokens.color.purple,
  'regime-detection': tokens.color.cyan,
  'strategy': tokens.color.blue,
  'paper-trading': tokens.color.green,
  'live-trading': tokens.color.amber,
  'risk-management': tokens.color.purple,
  'strategies': tokens.color.cyan,
  '2026': tokens.color.green,
  'market-analysis': tokens.color.blue,
  'diversification': tokens.color.amber,
  'global-markets': tokens.color.cyan,
  'backtesting': tokens.color.amber,
  'engineering': tokens.color.purple,
  'congress-trading': tokens.color.green,
  'stock-act': tokens.color.amber,
  'automation': tokens.color.cyan,
};

function formatDate(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

export default function BlogPage() {
  usePageTitle('Blog');

  const sorted = [...blogPosts].sort((a, b) => new Date(b.date) - new Date(a.date));

  return (
    <div className={s.page}>
      <SEO
        title="Blog — Algorithmic Trading Insights"
        description="Expert insights on algorithmic trading, ML strategies, risk management, and market analysis. New articles weekly from the Aura Alpha research team."
        keywords="algorithmic trading blog, trading strategies, machine learning trading, regime detection, quant trading"
        url="https://auraalpha.cc/blog"
      />
      <PublicNav />

      {/* Hero */}
      <div className={s.hero}>
        <h1 className={s.heroTitle}>Aura Alpha Blog</h1>
        <p className={s.heroSubtitle}>
          Insights on algorithmic trading, strategy development, risk management,
          and the technology behind autonomous trading systems.
        </p>
      </div>

      {/* Posts Grid */}
      <div className={s.postsContainer}>
        <div className={s.postsList}>
          {sorted.map((post, idx) => (
            <Link
              key={post.slug}
              to={`/blog/${post.slug}`}
              className={s.postLink}
            >
              <article className={s.postCard}>
                {/* Meta row */}
                <div className={s.postMeta}>
                  <span>{formatDate(post.date)}</span>
                  <span className={s.metaSep}>|</span>
                  <span>{post.readTime}</span>
                </div>

                {/* Title — dynamic fontSize based on index */}
                <h2
                  className={s.postTitle}
                  style={{ fontSize: idx === 0 ? 24 : 20 }}
                >
                  {post.title}
                </h2>

                {/* Excerpt */}
                <p className={s.postExcerpt}>{post.excerpt}</p>

                {/* Tags — dynamic colors */}
                <div className={s.tagsRow}>
                  {post.tags.map(tag => {
                    const c = TAG_COLORS[tag] || tokens.color.blue;
                    return (
                      <span
                        key={tag}
                        className={s.tag}
                        style={{
                          background: `color-mix(in srgb, ${c} 12%, transparent)`,
                          color: c,
                          border: `1px solid color-mix(in srgb, ${c} 20%, transparent)`,
                        }}
                      >
                        {tag}
                      </span>
                    );
                  })}
                </div>
              </article>
            </Link>
          ))}
        </div>
      </div>

      <PublicFooter />
    </div>
  );
}
